CODE_EXAMPLE:
// Query
public boolean attributeExists(String name) {
    return attributes.containsKey(name);
}
// Command
public void setAttribute(String name, String value) {
    attributes.put(name, value);
}

// Clear usage
if (attributeExists("username")) {
    setAttribute("username", "bob");
}

UNIT_TEST_EXAMPLE:
@Test
public void setAttribute_doesNotReturnValue() throws NoSuchMethodException {
    Method m = Config.class.getMethod("setAttribute", String.class, String.class);
    assertEquals(void.class, m.getReturnType());
}

@Test
public void attributeExists_returnsFalseForMissingKey() {
    Config config = new Config();
    assertFalse(config.attributeExists("missing"));
}
